import scala.collection.mutable.ArrayBuffer

def popcountDepth(x: Long): Int = {
    if (x == 1) 0
    else {
        var steps = 0
        var n = x
        while (n != 1) {
            n = java.lang.Long.bitCount(n)
            steps += 1
        }
        steps
    }
}

class Fenw(val size: Int) {
    private val n = size
    private val tree: Array[Long] = Array.ofDim(n + 1)

    def add(i: Int, v: Int): Unit = {
        var idx = i + 1
        while (idx <= n) {
            tree(idx) += v
            idx += (idx & -idx)
        }
    }

    def prefixSum(i: Int): Long = {
        var s = 0L
        var idx = i + 1
        while (idx > 0) {
            s += tree(idx)
            idx -= (idx & -idx)
        }
        s
    }

    def sumRange(l: Int, r: Int): Long = {
        if (l > r) 0L
        else if (l == 0) prefixSum(r)
        else prefixSum(r) - prefixSum(l - 1)
    }
}

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
    val n = nums.length
    val trees = Array.tabulate(6)(_ => new Fenw(n))
    val depths = new Array[Int](n)

    for (i <- 0 until n) {
        val d = popcountDepth(nums(i))
        depths(i) = d
        if (d >= 0 && d <= 5) {
            trees(d).add(i, 1)
        }
    }

    val ans = ArrayBuffer[Long]()
    for (q <- queries) {
        if (q(0) == 1) {
            val l = q(1).toInt
            val r = q(2).toInt
            val k = q(3).toInt
            if (k >= 0 && k <= 5) {
                ans += trees(k).sumRange(l, r)
            } else {
                ans += 0L
            }
        } else if (q(0) == 2) {
            val idx = q(1).toInt
            val newVal = q(2)
            val newDepth = popcountDepth(newVal)
            val oldDepth = depths(idx)
            if (oldDepth != newDepth) {
                if (oldDepth >= 0 && oldDepth <= 5) {
                    trees(oldDepth).add(idx, -1)
                }
                if (newDepth >= 0 && newDepth <= 5) {
                    trees(newDepth).add(idx, 1)
                }
                depths(idx) = newDepth
            }
        }
    }
    ans.toArray
}
