import scala.collection.mutable.ArrayBuffer

def solve(nums: Array[Long], queries: Array[Array[Long]]): Array[Long] = {
  val answer = ArrayBuffer[Long]()
  val n = nums.length
  val depthCache = scala.collection.mutable.Map[Long, Int]()

  def popcount(x: Long): Int = {
    var count = 0
    var num = x
    while (num != 0) {
      count += 1
      num = num & (num - 1)
    }
    count
  }

  def computeDepth(x: Long): Int = {
    if (x == 1) return 0
    if (depthCache.contains(x)) return depthCache(x)

    var current = x
    var d = 0
    val path = scala.collection.mutable.ArrayBuffer[Long]()

    while (current != 1 && !depthCache.contains(current)) {
      path += current
      current = popcount(current).toLong
      d += 1
    }

    val baseDepth = if (current == 1) d else d + depthCache(current)
    var depth = baseDepth
    for (i <- path.indices) {
      depthCache(path(i)) = depth - i
    }

    baseDepth
  }

  // Precompute depths for all nums
  val depths = Array.ofDim[Int](n)
  for (i <- nums.indices) {
    depths(i) = computeDepth(nums(i))
  }

  for (query <- queries) {
    if (query(0) == 1) {
      val l = query(1).toInt
      val r = query(2).toInt
      val k = query(3).toInt
      var count = 0L
      for (i <- l to r) {
        if (depths(i) == k) count += 1
      }
      answer += count
    } else if (query(0) == 2) {
      val idx = query(1).toInt
      val newVal = query(2)
      nums(idx) = newVal
      depths(idx) = computeDepth(newVal)
    }
  }

  answer.toArray
