      n = n & (n - 1)
    }
    count
  }

  def computeDepth(x: Long): Int = {
    if (x == 1) return 0
    if (memo.contains(x)) return memo(x)

    val cnt = popcount(x)
    val depth = 1 + computeDepth(cnt.toLong)
    memo(x) = depth
    depth
  }

  val depths = nums.map(computeDepth)
  val answer = ArrayBuffer[Long]()
  val n = nums.length
  val depthCounts = Array.ofDim[Int](n, 6) // depth can be up to 5 (as per constraints)

  // Precompute prefix sums for each depth 0 to 5
  for (d <- 0 to 5) {
    var count = 0
    for (i <- 0 until n) {
      if (depths(i) == d) count += 1
      depthCounts(i)(d) = count
    }
  }

