    if (query(0) == 1) {
      val l = query(1).toInt
      val r = query(2).toInt
      val k = query(3).toInt

      if (k > 5) {
        answer += 0
      } else {
        val leftCount = if (l > 0) depthCounts(l - 1)(k) else 0
        val rightCount = depthCounts(r)(k)
        answer += (rightCount - leftCount)
      }
    } else if (query(0) == 2) {
      val idx = query(1).toInt
      val newVal = query(2)
      val oldDepth = depths(idx)
      val newDepth = computeDepth(newVal)

